  <div style={{ display: "flex", gap: 5, padding: "14px 16px", alignItems: "center" }}>
    {[0,1,2].map(i => <span key={i} style={{ width:8, height:8, borderRadius:"50%", background:"#6b7280", animation:"bounce 1.2s infinite", animationDelay:`${i*0.2}s` }} />)}
  </div>
